from flask import Flask, request, jsonify
import sqlite3
import string
import random
import smtplib

app = Flask(__name__)

# Database initialization
def init_db():
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS password_resets (
                        email TEXT PRIMARY KEY, 
                        token TEXT)''')
    conn.commit()
    conn.close()

# Generate random token
def generate_token(length=16):
    return ''.join(random.choices(string.ascii_letters + string.digits, k=length))

# Send email (dummy function for demonstration; replace with actual email sending)
def send_reset_email(email, token):
    # Demonstration purpose only, replace with actual SMTP email sending logic
    print(f'Sending email to {email} with reset link: http://example.com/reset/{token}')

# Password reset request endpoint
@app.route('/reset_password', methods=['POST'])
def reset_password():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    token = generate_token()

    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    cursor.execute('REPLACE INTO password_resets (email, token) VALUES (?, ?)', (email, token))
    conn.commit()
    conn.close()

    send_reset_email(email, token)

    return jsonify({'message': 'Reset link sent'}), 200

